import React, { useState } from "react";
import Editor from "@monaco-editor/react";

function CodeEditorPage() {
  const [code, setCode] = useState("// Start typing your code...");
  const [language, setLanguage] = useState("javascript");
  const [output, setOutput] = useState("");

  // Handle typing
  const handleEditorChange = (value) => {
    setCode(value);
  };

  // Fake Run (frontend only)
  const runCode = () => {
    setOutput("Running...\n\n" + code);
  };

  return (
    <div style={styles.container}>
      
      {/* Sidebar */}
      <div style={styles.sidebar}>
        <h3>Files</h3>
        <p>main.{language}</p>
      </div>

      {/* Main Section */}
      <div style={styles.main}>
        
        {/* Top Bar */}
        <div style={styles.topbar}>
          <div>
            <select
              value={language}
              onChange={(e) => setLanguage(e.target.value)}
              style={styles.select}
            >
              <option value="javascript">JavaScript</option>
              <option value="python">Python</option>
              <option value="cpp">C++</option>
              <option value="java">Java</option>
            </select>
          </div>

          <button style={styles.runBtn} onClick={runCode}>
            ▶ Run Code
          </button>
        </div>

        {/* Editor */}
        <Editor
          height="60vh"
          language={language}
          theme="vs-dark"
          value={code}
          onChange={handleEditorChange}
          options={{
            fontSize: 14,
            minimap: { enabled: true },
            automaticLayout: true,
          }}
        />

        {/* Output Console */}
        <div style={styles.console}>
          <h4>Output</h4>
          <pre>{output}</pre>
        </div>
      </div>
    </div>
  );
}

export default CodeEditorPage;

const styles = {
  container: {
    display: "flex",
    height: "100vh",
    backgroundColor: "#1e1e1e",
    color: "#ffffff", // better readability
  },
  sidebar: {
    width: "200px",
    backgroundColor: "#252526",
    padding: "10px",
    borderRight: "1px solid #333",
    boxSizing: "border-box", // prevents overflow
  },
  main: {
    flex: 1,
    display: "flex",
    flexDirection: "column",
  },
  topbar: {
    height: "50px",
    backgroundColor: "#333",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "0 10px",
  },
  select: {
    padding: "5px",
    backgroundColor: "#1e1e1e", // changed 'background' → 'backgroundColor'
    color: "#ffffff",
    border: "1px solid #555",
    outline: "none", // cleaner UI
  },
  runBtn: {
    padding: "6px 12px",
    backgroundColor: "#0e639c",
    color: "#ffffff",
    border: "none",
    cursor: "pointer",
    borderRadius: "4px", // nicer button
  },
  console: {
    height: "30vh",
    backgroundColor: "#1e1e1e",
    borderTop: "1px solid #333",
    padding: "10px",
    overflowY: "auto", // better than "auto"
    fontFamily: "monospace", // looks like VS Code console
  },
};
